const orders = [{cId: 1}, {cId: 1}, {cId: 2}];
const grouped = orders.reduce((acc, o) => {
  acc[o.cId] = (acc[o.cId] || 0) + 1;
  return acc;
}, {});
const filtered = Object.entries(grouped).filter(([_, cnt]) => cnt > 10);

List<Order> orders = Arrays.asList(new Order(1, 1), new Order(2, 1));
Map<Integer, Long> counted = orders.stream()
  .collect(Collectors.groupingBy(Order::getCId, Collectors.counting()));
Map<Integer, Long> filtered = counted.entrySet().stream()
  .filter(e -> e.getValue() > 10)
  .collect(Collectors.toMap(Map.Entry::getKey, Map.Entry::getValue));
